public class debug_test {
    public static void main(String[] args) {
        Document doc = Jsoup.parse("<img src=foo noshade='' nohref async=async autofocus=false>");
        Element img = doc.selectFirst("img");
        String actual = img.outerHtml();
        String expected = "<img src=\"foo\" noshade nohref async autofocus=\"false\">";

        System.out.println("Expected: " + expected);
        System.out.println("Actual  : " + actual);

        System.out.println("Test passes: " + expected.equals(actual));

        // Let's also look at individual attributes
        System.out.println("\nIndividual attributes:");
        for (org.jsoup.nodes.Attribute attr : img.attributes()) {
            System.out.println("  " + attr.getKey() + "=\"" + attr.getValue() + "\"");
        }
    }
}

